            if (is == null) throw new IllegalArgumentException("Private key not found on classpath: " + classpath);
            byte[] pem = is.readAllBytes();
            String s = new String(pem, StandardCharsets.US_ASCII)
                    .replace("-----BEGIN PRIVATE KEY-----", "")
                    .replace("-----END PRIVATE KEY-----", "")
                    .replaceAll("\\s", "");
