class SessionStore {
    private static class Entry {
        final SamlPrincipal principal;
        final Instant expiresAt;
        Entry(SamlPrincipal p, Instant exp) { this.principal = p; this.expiresAt = exp; }
    }

    private final int ttlSeconds;
    private final ConcurrentHashMap<String, Entry> sessions = new ConcurrentHashMap<>();

    SessionStore(int ttlSeconds) {
        this.ttlSeconds = ttlSeconds;
    }

    public String create(SamlPrincipal principal) {
        String id = UUID.randomUUID().toString();
        sessions.put(id, new Entry(principal, Instant.now().plusSeconds(ttlSeconds)));
        return id;
    }

    public SamlPrincipal get(String id) {
        if (!StringUtils.hasText(id)) return null;
        Entry e = sessions.get(id);
        if (e == null) return null;
        if (Instant.now().isAfter(e.expiresAt)) {
            sessions.remove(id);
            return null;
        }
        return e.principal;
    }

    public void invalidate(String id) {
        if (StringUtils.hasText(id)) sessions.remove(id);
    }
}

@RestController
@RequestMapping("/saml")
class SamlController {

    private final SamlSpApplication.SamlSpProperties props;
    private final SamlMessageService saml;
    private final SessionStore sessions;

    SamlController(SamlSpApplication.SamlSpProperties props, SamlMessageService saml, SessionStore sessions) {
        this.props = props;
        this.saml = saml;
        this.sessions = sessions;
    }

    @GetMapping(value = "/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public ResponseEntity<String> metadata() {
        String xml = MetadataBuilder.buildSpMetadata(props);
        return ResponseEntity.ok(xml);
    }

    @GetMapping("/login")
    public void login(@RequestParam(value = "return", required = false) String returnTo,
                      HttpServletResponse response) throws IOException {
        String relay = StringUtils.hasText(returnTo) ? returnTo : "/";
        CookieUtil.addHttpOnlyCookie(response, props.getRelayStateCookieName(), relay, 300);
        String redirect = saml.buildRedirectAuthnRequest(relay);
        response.setStatus(302);
        response.setHeader("Location", redirect);
    }

    @PostMapping(value = "/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public void acs(@RequestParam("SAMLResponse") String samlResponse,
                    @RequestParam(value = "RelayState", required = false) String relayState,
                    HttpServletRequest request,
                    HttpServletResponse response) throws IOException {
        SamlPrincipal principal = saml.consumePostResponse(samlResponse);
        String sid = sessions.create(principal);
        CookieUtil.addHttpOnlyCookie(response, props.getSessionCookieName(), sid, props.getSessionTtlSeconds());

        String target = relayState;
        if (!StringUtils.hasText(target)) {
            target = CookieUtil.getCookieValue(request, props.getRelayStateCookieName());
        }
        if (!StringUtils.hasText(target)) target = "/";
        response.setStatus(302);
        response.setHeader("Location", target);
    }

    @PostMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String sid = CookieUtil.getCookieValue(request, props.getSessionCookieName());
        sessions.invalidate(sid);
        CookieUtil.clearCookie(response, props.getSessionCookieName());
        response.setStatus(302);
        response.setHeader("Location", "/");
    }

    @GetMapping("/me")
    public ResponseEntity<Map<String, Object>> me(HttpServletRequest request) {
        String sid = CookieUtil.getCookieValue(request, props.getSessionCookieName());
        SamlPrincipal p = sessions.get(sid);
        if (p == null) return ResponseEntity.status(401).body(Map.of("authenticated", false));
        Map<String, Object> body = new LinkedHashMap<>();
        body.put("authenticated", true);
        body.put("nameId", p.getNameId());
        body.put("attributes", p.getAttributes());
        body.put("sessionIndex", p.getSessionIndex());
        return ResponseEntity.ok(body);
    }
}

@Component
@Order(Ordered.HIGHEST_PRECEDENCE + 10)
class SamlSessionAuthFilter extends OncePerRequestFilter {

    private final SamlSpApplication.SamlSpProperties props;
    private final SessionStore sessions;

    SamlSessionAuthFilter(SamlSpApplication.SamlSpProperties props, SessionStore sessions) {
        this.props = props;
        this.sessions = sessions;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {

        String path = request.getRequestURI();
        if (path.startsWith("/saml/") || path.equals("/") || path.startsWith("/public/")) {
            filterChain.doFilter(request, response);
            return;
        }

        String sid = CookieUtil.getCookieValue(request, props.getSessionCookieName());
        SamlPrincipal p = sessions.get(sid);
        if (p == null) {
            String returnTo = request.getRequestURI();
            if (StringUtils.hasText(request.getQueryString())) returnTo += "?" + request.getQueryString();
            response.setStatus(302);
            response.setHeader("Location", "/saml/login?return=" + URLEncoder.encode(returnTo, StandardCharsets.UTF_8));
            return;
        }

        request.setAttribute("samlPrincipal", p);
        filterChain.doFilter(request, response);
    }
}

class CookieUtil {
    static void addHttpOnlyCookie(HttpServletResponse response, String name, String value, int maxAgeSeconds) {
        String cookie = name + "=" + urlEncode(value)
                + "; Path=/; Max-Age=" + maxAgeSeconds
                + "; HttpOnly; SameSite=Lax";
        response.addHeader(HttpHeaders.SET_COOKIE, cookie);
    }

    static void clearCookie(HttpServletResponse response, String name) {
        String cookie = name + "=; Path=/; Max-Age=0; HttpOnly; SameSite=Lax";
        response.addHeader(HttpHeaders.SET_COOKIE, cookie);
    }

    static String getCookieValue(HttpServletRequest request, String name) {
        if (request.getCookies() == null) return null;
        for (jakarta.servlet.http.Cookie c : request.getCookies()) {
            if (name.equals(c.getName())) return urlDecode(c.getValue());
        }
        return null;
    }

    private static String urlEncode(String s) {
        return URLEncoder.encode(s, StandardCharsets.UTF_8);
    }

    private static String urlDecode(String s) {
        try {
            return java.net.URLDecoder.decode(s, StandardCharsets.UTF_8);
        } catch (Exception e) {
            return s;
        }
    }
}

class MetadataBuilder {

    static String buildSpMetadata(SamlSpApplication.SamlSpProperties props) {
        String certB64 = loadCertB64(props.getSpCertificateClasspath());
        String entityId = escape(props.getEntityId());
        String acs = escape(props.getAcsUrl());

        return "<?xml version=\"1.0\" encoding=\"UTF-8\"?>"
                + "<md:EntityDescriptor xmlns:md=\"urn:oasis:names:tc:SAML:2.0:metadata\" entityID=\"" + entityId + "\">"
                + "<md:SPSSODescriptor protocolSupportEnumeration=\"urn:oasis:names:tc:SAML:2.0:protocol\" AuthnRequestsSigned=\"" + props.isSignAuthnRequests() + "\" WantAssertionsSigned=\"" + props.isWantAssertionsSigned() + "\">"
                + "<md:KeyDescriptor use=\"signing\">"
                + "<ds:KeyInfo xmlns:ds=\"http://www.w3.org/2000/09/xmldsig#\">"
                + "<ds:X509Data><ds:X509Certificate>" + certB64 + "</ds:X509Certificate></ds:X509Data>"
                + "</ds:KeyInfo>"
                + "</md:KeyDescriptor>"
                + "<md:NameIDFormat>" + escape(props.getNameIdFormat()) + "</md:NameIDFormat>"
                + "<md:AssertionConsumerService index=\"0\" isDefault=\"true\" Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\" Location=\"" + acs + "\"/>"
                + "</md:SPSSODescriptor>"
                + "</md:EntityDescriptor>";
    }

    private static String loadCertB64(String classpath) {
        try (InputStream is = MetadataBuilder.class.getResourceAsStream(classpath.startsWith("/") ? classpath : "/" + classpath)) {
            if (is == null) throw new IllegalArgumentException("SP certificate not found: " + classpath);
            CertificateFactory cf = CertificateFactory.getInstance("X.509");
            X509Certificate cert = (X509Certificate) cf.generateCertificate(is);
            return Base64.getEncoder().encodeToString(cert.getEncoded());
        } catch (Exception e) {
            throw new IllegalStateException(e);
        }
    }

    private static String escape(String s) {
        if (s == null) return "";
        return s.replace("&", "&amp;").replace("\"", "&quot;").replace("<", "&lt;").replace(">", "&gt;");
    }
}

class ParserPoolHolder {
    private static final org.opensaml.core.xml.parse.ParserPool POOL = buildPool();

    private static org.opensaml.core.xml.parse.ParserPool buildPool() {
        org.opensaml.core.xml.parse.BasicParserPool pool = new org.opensaml.core.xml.parse.BasicParserPool();
        pool.setNamespaceAware(true);
        pool.setCoalescing(true);
        pool.setExpandEntityReferences(false);
        pool.setIgnoreComments(true);
        pool.setIgnoreElementContentWhitespace(true);
        pool.setXincludeAware(false);
        try {
            pool.initialize();
        } catch (org.opensaml.core.xml.parse.XMLParserException e) {
            throw new IllegalStateException(e);
        }
        return pool;
    }

    static Element parse(byte[] xmlBytes) {
        try {
            return POOL.parse(new java.io.ByteArrayInputStream(xmlBytes)).getDocumentElement();
        } catch (org.opensaml.core.xml.parse.XMLParserException e) {
            throw new IllegalArgumentException("XML parse error", e);
        }
    }
}

class SerializeSupport {
    static String nodeToString(org.w3c.dom.Node node) {
        try {
            javax.xml.transform.TransformerFactory tf = javax.xml.transform.TransformerFactory.newInstance();
            javax.xml.transform.Transformer t = tf.newTransformer();
            t.setOutputProperty(javax.xml.transform.OutputKeys.OMIT_XML_DECLARATION, "yes");
            t.setOutputProperty(javax.xml.transform.OutputKeys.ENCODING, "UTF-8");
            t.setOutputProperty(javax.xml.transform.OutputKeys.INDENT, "no");
            java.io.StringWriter sw = new java.io.StringWriter();
            t.transform(new javax.xml.transform.dom.DOMSource(node), new javax.xml.transform.stream.StreamResult(sw));
            return sw.toString();
        } catch (Exception e) {
            throw new IllegalStateException(e);
        }
    }
}